function assuranceFieldHtml(field, record) {
  const [name, label, kind, values] = field;
  const value = record[name] || "";
  let control;
  if (kind === "textarea")
    control = `<textarea name="${name}">${esc2(value)}</textarea>`;
  else if (kind === "select")
    control = `<select name="${name}">${values.map((option) => `<option ${option === value ? "selected" : ""}>${esc2(option)}</option>`).join("")}</select>`;
  else if (["requirements", "components", "hazards", "evidence", "deviations", "baselines", "claims"].includes(kind))
    control = `<select name="${name}">${assuranceOptions(kind, value)}</select>`;
  else
    control = `<input type="${kind === "date" ? "date" : "text"}" name="${name}" value="${esc2(value)}" placeholder="${esc2(values || "")}" />`;
  return `<label class="${kind === "textarea" ? "wide" : ""}"><span>${esc2(label)}</span>${control}</label>`;
}
