function renderFaultTreeLineNumbers(errorLine) {
  const source = $("#fault-tree-source");
  const gutter = $("#fault-tree-line-numbers");
  const lineCount = Math.max(1, source.value.split(/\r?\n/).length);
  gutter.innerHTML = Array.from({ length: lineCount }, (_, index) => `<span${index + 1 === errorLine ? ' class="error"' : ""}>${index + 1}</span>`).join("");
  gutter.style.width = `${Math.max(3, String(lineCount).length + 1.4)}ch`;
  gutter.scrollTop = source.scrollTop;
}
function focusFaultTreeLine(line) {
  if (!Number.isInteger(line) || line < 1)
    return;
  if (faultTreeEditorLayer !== "All") {
    commitFaultTreeEditorDraft();
    state.faultTree.activeLayer = "All";
    faultTreeEditorLayer = "All";
    persistState();
    renderFaultTree();
  }
  const editor = $("#fault-tree-source");
  const lines = editor.value.split(/\r?\n/);
  const start = lines.slice(0, line - 1).reduce((offset, text) => offset + text.length + 1, 0);
  const end = start + (lines[line - 1] || "").length;
  const lineHeight = Number.parseFloat(getComputedStyle(editor).lineHeight) || 19;
  editor.focus();
  editor.setSelectionRange(start, end);
  editor.scrollTop = Math.max(0, (line - 2) * lineHeight);
  renderFaultTreeLineNumbers(line);
}
