$("#assurance-form").addEventListener("submit", (event) => {
  event.preventDefault();
  const form = event.target;
  const data = formValues(form);
  const kind = $("#assurance-record-type").value;
  const existingId = data.recordId;
  try {
    data.id = requireIdentifier(data.id, kind === "hazard" ? "Hazard identifier" : "Record identifier");
    if (kind !== "hazard") {
      data.id = requireUniqueIdentifier(state.assurance[kind], data.id, "Record identifier", { ignoreField: "id", ignoreValue: existingId });
      data.title = requireValue(data.title, "Title");
    }
    if (kind === "tests") {
      data.requirement = requireValue(data.requirement, "Linked requirement");
      data.objective = requireValue(data.objective, "Objective");
      data.expected = requireValue(data.expected, "Expected result");
      data.configuration = requireValue(data.configuration, "Configuration");
      if (data.status === "Passed" && (!data.actual.trim() || !approvedEvidence(data.evidence)))
        throw new Error("A passed V&V record needs an actual result and approved evidence.");
      if (data.status === "Failed" && !data.deviation)
        throw new Error("A failed V&V record must link an issue or deviation.");
    }
    if (kind === "evidence") {
      data.reference = requireValue(data.reference, "Evidence reference");
      data.version = requireValue(data.version, "Evidence version");
    }
    if (kind === "deviations" && data.status === "Closed" && (!data.disposition.trim() || !approvedEvidence(data.closureEvidence)))
      throw new Error("A closed deviation needs a disposition and approved closure evidence.");
    if (kind === "changes" && ["Approved", "Implemented"].includes(data.decision) && (!data.safetyImpact.trim() || !approvedEvidence(data.evidence)))
      throw new Error("An approved or implemented change needs an impact assessment and approved evidence.");
    if (kind === "baselines" && data.status === "Approved" && (!data.approver.trim() || !data.date))
      throw new Error("An approved baseline needs an approver and baseline date.");
    if (kind === "reviews" && data.status === "Complete" && (!data.decision.trim() || !approvedEvidence(data.evidence)))
      throw new Error("A completed review needs a decision and approved review evidence.");
    if (kind === "interfaces" && data.status === "Verified" && !data.failureResponse.trim())
      throw new Error("A verified interface needs a documented failure response.");
    if (kind === "ram" && data.status === "Demonstrated" && !data.method.trim())
      throw new Error("A demonstrated RAM objective needs a demonstration method.");
    if (kind === "claims" && data.status === "Supported" && !approvedEvidence(data.evidence))
      throw new Error("A supported safety-case claim needs approved evidence.");
    if (kind === "hazard" && data.status === "Closed" && (!data.control.trim() || !data.residualRisk.trim() || !approvedEvidence(data.closureEvidence)))
      throw new Error("A closed hazard needs a control, residual-risk rationale, and approved closure evidence.");
  } catch (error) {
    return handleFormError(error);
  }
  if (kind === "hazard") {
    const hazard = state.hazards.find((item) => item.id === data.id);
    if (!hazard)
      return handleFormError(new Error("Select an existing hazard."));
    Object.assign(hazard, { owner: data.owner, control: data.control, residualRisk: data.residualRisk, closureEvidence: data.closureEvidence, status: data.status });
    auditAssurance("Updated", "hazard", hazard.id, hazard.status);
  } else {
    const record = Object.fromEntries(assuranceSchemas[kind].map(([name]) => [name, data[name] || ""]));
    const existing = state.assurance[kind].find((item) => item.id === existingId);
    if (kind === "baselines" && record.status === "Approved") {
      record.inventory ||= `${state.components.length} components, ${state.hazards.length} hazards, ${state.requirements.length} requirements, ${state.workflow.activities.length} workflow activities, ${state.assurance.tests.length} V&V records`;
      record.snapshot = existing?.snapshot || structuredClone({
        plantuml: state.plantuml,
        components: state.components,
        hazards: state.hazards,
        situations: state.situations,
        requirements: state.requirements,
        safetyGoals: state.safetyGoals,
        hara: state.hara,
        silAssessments: state.silAssessments,
        quantitative: state.quantitative,
        fmeda: state.fmeda,
        workflow: state.workflow,
        fmea: state.fmea,
        assurance: Object.fromEntries(Object.entries(state.assurance).filter(([key]) => !["baselines", "audit"].includes(key)))
      });
    }
    if (existing)
      Object.assign(existing, record);
    else
      state.assurance[kind].push(record);
    auditAssurance(existing ? "Updated" : "Created", kind, record.id, record.status || record.decision || "");
  }
  $("#assurance-record-type").disabled = false;
  $("#assurance-dialog").close();
  save();
});
