$("#fault-tree-export-btn").addEventListener("click", () => {
  const dsl = $("#fault-tree-source").value;
  if (!dsl.trim())
    return alert("No fault tree to export. Create or load a fault tree first.");
  const model = parseFaultTreeDsl(dsl);
  const menu = document.createElement("div");
  menu.style.cssText = `position:fixed;top:200px;left:50%;transform:translateX(-50%);background:white;border:1px solid #ddd;border-radius:4px;box-shadow:0 2px 8px rgba(0,0,0,0.2);z-index:9999;min-width:200px`;
  menu.innerHTML = `
    <button style="display:block;width:100%;padding:10px;border:none;background:none;text-align:left;cursor:pointer;border-bottom:1px solid #eee" id="export-dsl">\uD83D\uDCC4 Export DSL (.ft)</button>
    <button style="display:block;width:100%;padding:10px;border:none;background:none;text-align:left;cursor:pointer;border-bottom:1px solid #eee" id="export-cutsets">\uD83D\uDCCA Export Cut Sets (.csv)</button>
    <button style="display:block;width:100%;padding:10px;border:none;background:none;text-align:left;cursor:pointer" id="export-json">\uD83D\uDCCB Export as JSON</button>
  `;
  document.body.appendChild(menu);
  document.getElementById("export-dsl").addEventListener("click", () => {
    const fileName = (model.top || "fault-tree").toLowerCase() + ".ft";
    const link = document.createElement("a");
    link.href = URL.createObjectURL(new Blob([dsl], { type: "text/plain" }));
    link.download = fileName;
    link.click();
    document.body.removeChild(menu);
  });
  document.getElementById("export-cutsets").addEventListener("click", () => {
    const result = faultTreeCutSets(model, model.top);
    if (result.nonCoherent)
      return alert("Cut-set CSV is unavailable for a tree with NOT, NAND, NOR, or XOR gates. Use a dedicated Boolean/probabilistic analysis.");
    const cutSets = result.sets;
    let csv = `Order,Cut Set,Event IDs
`;
    const byOrder = {};
    cutSets.forEach((cs) => {
      const order = cs.length;
      if (!byOrder[order])
        byOrder[order] = [];
      byOrder[order].push(cs);
    });
    Object.keys(byOrder).sort((a, b) => parseInt(a) - parseInt(b)).forEach((order) => {
      byOrder[order].forEach((cs) => {
        csv += `${order},"${cs.join(", ")}","${cs.join("; ")}"
`;
      });
    });
    const fileName = (model.top || "cut-sets").toLowerCase() + ".csv";
    const link = document.createElement("a");
    link.href = URL.createObjectURL(new Blob([csv], { type: "text/csv" }));
    link.download = fileName;
    link.click();
    document.body.removeChild(menu);
  });
  document.getElementById("export-json").addEventListener("click", () => {
    const json = JSON.stringify({ model: { ...model, nodes: [...model.nodes.values()] }, qualitativeAnalysis: faultTreeCutSets(model, model.top) }, null, 2);
    const fileName = (model.top || "fault-tree").toLowerCase() + ".json";
    const link = document.createElement("a");
    link.href = URL.createObjectURL(new Blob([json], { type: "application/json" }));
    link.download = fileName;
    link.click();
    document.body.removeChild(menu);
  });
  const closeMenu = (e) => {
    if (e.key === "Escape") {
      document.body.removeChild(menu);
      document.removeEventListener("keydown", closeMenu);
    }
  };
  document.addEventListener("keydown", closeMenu);
});
$("#fault-tree-save-btn").addEventListener("click", () => {
  try {
    commitFaultTreeEditorDraft();
    parseFaultTreeDsl(state.faultTree.dsl);
    save();
  } catch (error) {
    const line = Number(String(error.message || "").match(/line\s+(\d+)/i)?.[1]);
    renderFaultTree();
    if (Number.isFinite(line))
      focusFaultTreeLine(line);
    handleFormError(error);
  }
});
$("#fault-tree-generate-btn").addEventListener("click", () => {
  if (!applyArchitectureSource($("#plantuml-source").value))
    return alert("Fix the UML source before generating a fault tree.");
  if (!state.components.length)
    return alert("No architecture components found. Define component-like entities in UML source, then generate the starter tree.");
  state.faultTree.dsl = faultTreeFromArchitectureDsl();
  state.faultTree.activeLayer = "All";
  faultTreeEditorLayer = "All";
  state.faultTree.layerCount = Math.max(state.faultTree.layerCount || 3, 2);
  save();
  alert(`${state.components.length} architecture components were expanded into starter malfunctioning behaviours. Refine the top event and remove inapplicable events before using the analysis.`);
});
$("#fault-tree-layer").addEventListener("change", (event) => {
  commitFaultTreeEditorDraft();
  state.faultTree.activeLayer = event.target.value;
  faultTreeEditorLayer = state.faultTree.activeLayer;
  persistState();
  $("#fault-tree-source").value = faultTreeEditorLayer === "All" ? state.faultTree.dsl : filteredFaultTreeDsl(state.faultTree.dsl, faultTreeEditorLayer);
  renderFaultTree();
});
$("#fault-tree-layer-count").addEventListener("change", (event) => {
  const value = Number(event.target.value);
  if (!Number.isInteger(value) || value < 1 || value > 12)
    return alert("Layer count must be an integer between 1 and 12.");
  state.faultTree.layerCount = value;
  if (!configuredFaultTreeLayers().includes(state.faultTree.activeLayer))
    state.faultTree.activeLayer = "All";
  faultTreeEditorLayer = state.faultTree.activeLayer;
  save();
});
function adjustFaultTreeZoom(change) {
  faultTreeZoom = Math.max(0.5, Math.min(2.5, Math.round((faultTreeZoom + change) * 10) / 10));
  renderFaultTree();
}
$("#fault-tree-zoom-in").addEventListener("click", () => adjustFaultTreeZoom(0.1));
$("#fault-tree-zoom-out").addEventListener("click", () => adjustFaultTreeZoom(-0.1));
$("#fault-tree-zoom-reset").addEventListener("click", () => {
  faultTreeZoom = 1;
  renderFaultTree();
});
$("#fault-tree-search").addEventListener("input", (event) => {
  faultTreeSearch = event.target.value;
  renderFaultTree();
});
$("#fault-tree-analysis").addEventListener("change", (event) => {
  const target = event.target;
  if (target.id === "fault-tree-cutset-limit") {
    faultTreeCutSetLimit = Number(target.value);
    renderFaultTree();
  }
});
$("#fault-tree-analysis").addEventListener("click", (event) => {
  const target = eventElement(event).closest("[data-fault-tree-go-to-line]");
  if (target)
    focusFaultTreeLine(Number(target.dataset.faultTreeGoToLine));
});
$("#render-btn").addEventListener("click", () => {
  clearTimeout(architectureSourceTimer);
  applyArchitectureSource($("#plantuml-source").value);
});
$("#export-btn").addEventListener("click", () => {
  const source = $("#plantuml-source").value;
  if (!applyArchitectureSource(source, { remember: false }))
    activeArchitectureDiagram().sourceDraft = source;
  persistState();
  const project = projectEnvelope();
  const slug = activeWorkspace().name.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "") || "safety-workspace";
  const blob = new Blob([JSON.stringify(project, null, 2)], { type: "application/json" });
  const link = Object.assign(document.createElement("a"), { href: URL.createObjectURL(blob), download: `${slug}.asasbits.json` });
  link.click();
  URL.revokeObjectURL(link.href);
});
renderAll();
showView(requestedView(), "replace");
hydrateRegistryFromServer();
